+        store.load_or_init(&policy, 1000).unwrap();
+        let update = store.update_wealth(&policy, 1000, 5).unwrap();
+        // reward = 0.01 * 5 = 0.05
+        // wealth_next = (0.05 - 0.001 + 0.05).max(0) = 0.099
